//! Compressed all-intra H.264 I-slice encoder: Intra_16x16 prediction + integer
//! transform/quant + CAVLC residual coding. The X-sized replacement for I_PCM.
//!
//! Pure Rust, std+alloc only, no external crates, no threads — wasm32-safe.
//!
//! Strategy (ITU-T H.264 §7.3.5 / §8.3.3 / §8.5 / §9.2):
//!   * Every macroblock is coded as **I_16x16** (one luma prediction mode for the
//!     whole 16×16, a separate Hadamard-transformed luma-DC block, 16 luma-AC
//!     blocks, and 4:2:0 chroma = a 2×2 Hadamard DC block per component plus 4 AC
//!     blocks per component).
//!   * The encoder reconstructs each macroblock exactly as the decoder will, so
//!     intra prediction from already-coded neighbours is bit-exact and the per-4×4
//!     TotalCoeff values used for the CAVLC `nC` context are exact.
//!   * `mb_type` carries (Intra16x16PredMode, CodedBlockPatternChroma,
//!     CodedBlockPatternLuma∈{0,15}); we choose mode 2 (DC) always and set the
//!     CBP bits from the actual coded residual so flat regions cost almost nothing.
//!
//! Decode-verified against ffmpeg (see the `#[cfg(test)]` ladder at the bottom).

use crate::h264_bitstream::{nal_unit, BitWriter};
use crate::h264_cavlc::write_residual_4x4;
use crate::h264_transform::{dequant4x4, fdct4x4, idct4x4, quant4x4, ZIGZAG4};

#[inline]
fn ceil_div(a: u32, b: u32) -> u32 {
    (a + b - 1) / b
}

// ─────────────────────────────────────────────────────────────────────────────
// DC transforms (Hadamard) and DC quant/dequant
// ─────────────────────────────────────────────────────────────────────────────

/// Forward 4×4 Hadamard transform of the 16 luma DC coefficients (§8.5.10).
fn hadamard4x4(blk: &[i32; 16]) -> [i32; 16] {
    let mut tmp = [0i32; 16];
    // rows
    for i in 0..4 {
        let d = &blk[i * 4..i * 4 + 4];
        let s0 = d[0] + d[2];
        let s1 = d[0] - d[2];
        let s2 = d[1] - d[3];
        let s3 = d[1] + d[3];
        tmp[i * 4] = s0 + s3;
        tmp[i * 4 + 1] = s1 + s2;
        tmp[i * 4 + 2] = s1 - s2;
        tmp[i * 4 + 3] = s0 - s3;
    }
    let mut out = [0i32; 16];
    // columns
    for j in 0..4 {
        let s0 = tmp[j] + tmp[8 + j];
        let s1 = tmp[j] - tmp[8 + j];
        let s2 = tmp[4 + j] - tmp[12 + j];
        let s3 = tmp[4 + j] + tmp[12 + j];
        out[j] = s0 + s3;
        out[4 + j] = s1 + s2;
        out[8 + j] = s1 - s2;
        out[12 + j] = s0 - s3;
    }
    out
}

/// Inverse 4×4 Hadamard transform of luma DC (§8.5.10), no normalisation shift
/// (the >>6-style scaling is folded into the DC dequant below).
fn ihadamard4x4(blk: &[i32; 16]) -> [i32; 16] {
    let mut tmp = [0i32; 16];
    for i in 0..4 {
        let d = &blk[i * 4..i * 4 + 4];
        let s0 = d[0] + d[2];
        let s1 = d[0] - d[2];
        let s2 = d[1] - d[3];
        let s3 = d[1] + d[3];
        tmp[i * 4] = s0 + s3;
        tmp[i * 4 + 1] = s1 + s2;
        tmp[i * 4 + 2] = s1 - s2;
        tmp[i * 4 + 3] = s0 - s3;
    }
    let mut out = [0i32; 16];
    for j in 0..4 {
        let s0 = tmp[j] + tmp[8 + j];
        let s1 = tmp[j] - tmp[8 + j];
        let s2 = tmp[4 + j] - tmp[12 + j];
        let s3 = tmp[4 + j] + tmp[12 + j];
        out[j] = s0 + s3;
        out[4 + j] = s1 + s2;
        out[8 + j] = s1 - s2;
        out[12 + j] = s0 - s3;
    }
    out
}

// V[qp%6] for the DC corner position (position class 0), used for DC dequant.
const V_DC: [i32; 6] = [10, 11, 13, 14, 16, 18];
// MF[qp%6] corner (position class 0) for DC quant.
const MF_DC: [i32; 6] = [13107, 11916, 10082, 9362, 8192, 7282];

/// Quantise the 16 luma-DC Hadamard coefficients (§8.5.10.2).
fn quant_luma_dc(dc: &[i32; 16], qp: u8) -> [i32; 16] {
    let qp = qp.min(51) as usize;
    let qbits = 15 + (qp / 6) as i32;
    let mf = MF_DC[qp % 6];
    // For DC the standard uses qbits+1 and 2*f rounding.
    let f = 1i64 << qbits; // == 2*(1<<(qbits-1))
    let mut out = [0i32; 16];
    for i in 0..16 {
        let sign = dc[i].signum() as i64;
        let abs = (dc[i].abs() as i64) * (mf as i64);
        out[i] = (sign * ((abs + f) >> (qbits + 1))) as i32;
    }
    out
}

/// Dequantise the 16 luma-DC levels back to scaled DC coefficients (§8.5.10.2).
/// Applies inverse Hadamard then the spec's DC scaling.
fn dequant_luma_dc(levels: &[i32; 16], qp: u8) -> [i32; 16] {
    let qp = qp.min(51) as i32;
    let qp_div6 = qp / 6;
    let qp_mod6 = (qp % 6) as usize;
    let v = V_DC[qp_mod6];
    let f = ihadamard4x4(levels);
    let mut out = [0i32; 16];
    if qp_div6 >= 2 {
        let shift = qp_div6 - 2;
        for i in 0..16 {
            out[i] = (f[i] * v) << shift;
        }
    } else {
        // qp_div6 ∈ {0,1}: ( f*V + 2^(1-qp/6) ) >> (2 - qp/6)
        let shift = 2 - qp_div6;
        let round = 1i32 << (1 - qp_div6);
        for i in 0..16 {
            out[i] = (f[i] * v + round) >> shift;
        }
    }
    out
}

/// Forward 2×2 Hadamard for chroma DC (§8.5.11.1).
fn hadamard2x2(blk: &[i32; 4]) -> [i32; 4] {
    let a = blk[0];
    let b = blk[1];
    let c = blk[2];
    let d = blk[3];
    [a + b + c + d, a - b + c - d, a + b - c - d, a - b - c + d]
}

/// Quantise chroma DC (§8.5.11.2): uses the same MF corner value, shifted.
fn quant_chroma_dc(dc: &[i32; 4], qp: u8) -> [i32; 4] {
    let qp = qp.min(51) as usize;
    let qbits = 15 + (qp / 6) as i32;
    let mf = MF_DC[qp % 6];
    let f = 1i64 << qbits;
    let mut out = [0i32; 4];
    for i in 0..4 {
        let sign = dc[i].signum() as i64;
        let abs = (dc[i].abs() as i64) * (mf as i64);
        out[i] = (sign * ((abs + f) >> (qbits + 1))) as i32;
    }
    out
}

/// Dequantise chroma DC (§8.5.11.2): inverse 2×2 Hadamard then DC scaling.
fn dequant_chroma_dc(levels: &[i32; 4], qp: u8) -> [i32; 4] {
    let qp = qp.min(51) as i32;
    let qp_div6 = qp / 6;
    let qp_mod6 = (qp % 6) as usize;
    let v = V_DC[qp_mod6];
    let f = hadamard2x2(levels); // inverse 2×2 Hadamard == forward (self-inverse up to scale)
    let mut out = [0i32; 4];
    // §8.5.11.2: dcCij = (f · LevelScale4x4(qP%6,0,0) << (qP/6)) >> 5, where
    // LevelScale4x4 = weightScale(=16 for the flat default matrix) · normAdjust(=V_DC).
    // The earlier code dropped the ×16 weightScale, dequantizing chroma DC 16×
    // too weakly → whole-MB chroma DC shifted toward 128 (spurious colour blocks
    // on saturated content). The AC path (dequant4x4) cancels the 16 via its >>4;
    // chroma DC uses >>5 so the 16 must be applied explicitly.
    for i in 0..4 {
        out[i] = ((f[i] * v * 16) << qp_div6) >> 5;
    }
    out
}

/// Chroma QP from luma QP (§8.5.8, chroma_qp_index_offset == 0).
fn chroma_qp(qp: u8) -> u8 {
    const TAB: [u8; 22] = [
        29, 30, 31, 32, 32, 33, 34, 34, 35, 35, 36, 36, 37, 37, 37, 38, 38, 38, 39, 39, 39, 39,
    ];
    let qpi = qp.min(51) as i32; // offset 0
    if qpi < 30 {
        qpi as u8
    } else {
        TAB[(qpi - 30) as usize]
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Plane helpers
// ─────────────────────────────────────────────────────────────────────────────

#[inline]
fn at(p: &[u8], w: u32, h: u32, x: u32, y: u32) -> u8 {
    let cx = x.min(w - 1);
    let cy = y.min(h - 1);
    p[(cy * w + cx) as usize]
}

/// A reconstructed picture buffer (one plane). Used so prediction reads exactly
/// what the decoder reconstructs.
struct Plane {
    data: Vec<u8>,
    w: u32,
    h: u32,
}

impl Plane {
    fn new(w: u32, h: u32) -> Self {
        Plane {
            data: vec![0u8; (w * h) as usize],
            w,
            h,
        }
    }
    #[inline]
    fn get(&self, x: i32, y: i32) -> u8 {
        let cx = x.clamp(0, self.w as i32 - 1) as u32;
        let cy = y.clamp(0, self.h as i32 - 1) as u32;
        self.data[(cy * self.w + cx) as usize]
    }
    #[inline]
    fn set(&mut self, x: u32, y: u32, v: u8) {
        self.data[(y * self.w + x) as usize] = v;
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// nC TotalCoeff context grid (one entry per 4×4 luma block, and per chroma 4×4)
// ─────────────────────────────────────────────────────────────────────────────

/// Per-4×4-block TotalCoeff store for the whole picture, indexed in 4×4 units.
struct CoeffCtx {
    luma: Vec<i32>, // -1 = not yet coded / unavailable, else TotalCoeff
    bw4: u32,       // width in 4×4 blocks
    bh4: u32,
    cb: Vec<i32>,
    cr: Vec<i32>,
    cbw4: u32,
    cbh4: u32,
}

impl CoeffCtx {
    fn new(width: u32, height: u32) -> Self {
        let bw4 = ceil_div(width, 16) * 4;
        let bh4 = ceil_div(height, 16) * 4;
        let cbw4 = ceil_div(width, 16) * 2;
        let cbh4 = ceil_div(height, 16) * 2;
        CoeffCtx {
            luma: vec![-1; (bw4 * bh4) as usize],
            bw4,
            bh4,
            cb: vec![-1; (cbw4 * cbh4) as usize],
            cr: vec![-1; (cbw4 * cbh4) as usize],
            cbw4,
            cbh4,
        }
    }

    /// nC for a luma 4×4 block at (bx,by) in 4×4 units (§9.2.1).
    fn nc_luma(&self, bx: i32, by: i32) -> i32 {
        nc_from(&self.luma, self.bw4 as i32, self.bh4 as i32, bx, by)
    }
    fn set_luma(&mut self, bx: u32, by: u32, tc: i32) {
        self.luma[(by * self.bw4 + bx) as usize] = tc;
    }
    fn nc_chroma(&self, is_cr: bool, bx: i32, by: i32) -> i32 {
        let g = if is_cr { &self.cr } else { &self.cb };
        nc_from(g, self.cbw4 as i32, self.cbh4 as i32, bx, by)
    }
    fn set_chroma(&mut self, is_cr: bool, bx: u32, by: u32, tc: i32) {
        let g = if is_cr { &mut self.cr } else { &mut self.cb };
        g[(by * self.cbw4 + bx) as usize] = tc;
    }
}

/// Per-4×4-block Intra_4x4 prediction-mode store for the whole picture, indexed
/// in 4×4 luma units. Used to derive `predIntra4x4PredMode` (the min of the
/// left/top neighbour modes) across MB boundaries. A value of `-1` marks a block
/// that is unavailable or not coded as Intra_4x4 (so it contributes DC=2 to the
/// neighbour-mode prediction, per §8.3.1.1).
struct I4x4ModeCtx {
    modes: Vec<i32>,
    bw4: u32,
    bh4: u32,
}

impl I4x4ModeCtx {
    fn new(width: u32, height: u32) -> Self {
        let bw4 = ceil_div(width, 16) * 4;
        let bh4 = ceil_div(height, 16) * 4;
        I4x4ModeCtx {
            modes: vec![-1; (bw4 * bh4) as usize],
            bw4,
            bh4,
        }
    }
    /// Neighbour mode at (bx,by) in 4×4 units; DC(2) if outside the picture or
    /// not coded as Intra_4x4 (stored as -1).
    fn mode_or_dc(&self, bx: i32, by: i32) -> i32 {
        if bx < 0 || by < 0 || bx >= self.bw4 as i32 || by >= self.bh4 as i32 {
            return 2;
        }
        let v = self.modes[(by * self.bw4 as i32 + bx) as usize];
        if v < 0 {
            2
        } else {
            v
        }
    }
    fn set(&mut self, bx: u32, by: u32, mode: i32) {
        self.modes[(by * self.bw4 + bx) as usize] = mode;
    }
}

/// Generic nC derivation from a TotalCoeff grid (−1 = unavailable).
fn nc_from(grid: &[i32], gw: i32, gh: i32, bx: i32, by: i32) -> i32 {
    let avail = |x: i32, y: i32| -> Option<i32> {
        if x < 0 || y < 0 || x >= gw || y >= gh {
            return None;
        }
        let v = grid[(y * gw + x) as usize];
        if v < 0 {
            None
        } else {
            Some(v)
        }
    };
    let a = avail(bx - 1, by); // left
    let b = avail(bx, by - 1); // top
    match (a, b) {
        (Some(na), Some(nb)) => (na + nb + 1) >> 1,
        (Some(na), None) => na,
        (None, Some(nb)) => nb,
        (None, None) => 0,
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// 4×4 raster <-> zig-zag, and per-block TotalCoeff
// ─────────────────────────────────────────────────────────────────────────────

/// Reorder a raster-order 4×4 coefficient block into zig-zag scan order.
fn to_zigzag(raster: &[i32; 16]) -> [i32; 16] {
    let mut z = [0i32; 16];
    for (zpos, &rpos) in ZIGZAG4.iter().enumerate() {
        z[zpos] = raster[rpos];
    }
    z
}

/// Reorder a 15-entry AC block (raster positions 1..15) into zig-zag order with
/// a forced-zero DC slot (zig-zag index 0). Used for Intra16x16/chroma AC where
/// the DC is coded separately. Returns a 16-slot zig-zag array with [0]==0.
fn ac_to_zigzag(raster: &[i32; 16]) -> [i32; 16] {
    let mut z = [0i32; 16];
    for (zpos, &rpos) in ZIGZAG4.iter().enumerate() {
        if zpos == 0 {
            z[0] = 0; // DC excluded
        } else {
            z[zpos] = raster[rpos];
        }
    }
    z
}

fn total_coeff(z: &[i32; 16], max_n: usize) -> i32 {
    let mut c = 0;
    for &v in z.iter().take(max_n) {
        if v != 0 {
            c += 1;
        }
    }
    c
}

// ─────────────────────────────────────────────────────────────────────────────
// Intra_16x16 DC prediction (the only luma mode we emit, mode 2)
// ─────────────────────────────────────────────────────────────────────────────

// Test-only switch to force the legacy fixed-mode path (luma DC=2, chroma DC=0)
// so the A/B PSNR/size comparison can measure mode selection against the old
// behaviour. THREAD-LOCAL so it never leaks into other tests running in
// parallel. Never set in production code.
#[cfg(test)]
thread_local! {
    static FORCE_FIXED_DC: core::cell::Cell<bool> = const { core::cell::Cell::new(false) };
}

#[cfg(test)]
fn force_fixed_dc() -> bool {
    FORCE_FIXED_DC.with(|c| c.get())
}
#[cfg(test)]
fn set_force_fixed_dc(v: bool) {
    FORCE_FIXED_DC.with(|c| c.set(v));
}
#[cfg(not(test))]
#[inline]
fn force_fixed_dc() -> bool {
    false
}

